const raw    = $input.first().json.content[0].text;
const usage  = $input.first().json.usage || {};
const tokensIn  = usage.input_tokens  || 0;
const tokensOut = usage.output_tokens || 0;
// claude-sonnet-4-6: $3/M input, $15/M output
const costEstimate = ((tokensIn / 1e6) * 3) + ((tokensOut / 1e6) * 15);

const fromName = $('Execute Workflow Trigger').first().json.from_name;
const name     = $('Execute Workflow Trigger').first().json.name;
const bizName  = $('Execute Workflow Trigger').first().json.business_name;

let parsed;
try {
  parsed = JSON.parse(raw.trim());
} catch (e) {
  parsed = {
    qualification_score:        5,
    qualification_score_reason: 'AI parse error — manual review needed',
    email_subject:              'Thanks for reaching out to CAIAC Digital',
    email_body:                 `Hi ${name},\n\nThank you for your interest in CAIAC Digital. We'd love to learn more about how we can help ${bizName}.\n\nCould we schedule a quick 15-minute call this week?\n\nBest,\n${fromName}\nCAIAC Digital`
  };
}

const disclaimer = `\n\n---\nThis message was drafted by AI on behalf of ${fromName}. A team member will follow up with you personally.`;

return [{
  json: {
    qualification_score:        parsed.qualification_score,
    qualification_score_reason: parsed.qualification_score_reason,
    email_subject:              parsed.email_subject,
    email_body:                 parsed.email_body + disclaimer,
    tokens_in:                  tokensIn,
    tokens_out:                 tokensOut,
    cost_estimate:              costEstimate,
  }
}];

return [{ json: {
  qualification_score: 0,
  qualification_score_reason: 'Lead scoring not enabled for this account',
  email_subject: '',
  email_body: '',
  tokens_in: 0,
  tokens_out: 0,
  cost_estimate: 0
}}];
